var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"그만!","JPN":"やめて！","ENG":"Enough!","TWN":"住手！"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"이제…","JPN":"もう……","ENG":"It's...","TWN":"好了……"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":" 그만해, 유피.","JPN":" やめて、ユピ。","ENG":" enough, Yuppie.","TWN":"可以了，悠菲。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"보물찾기는 나중에 해도 되는걸. 나 때문에 친구가 다치는 건 싫어.","JPN":"宝探しはまたやればいい。私のせいで周りの人が傷つくのは見たくない。","ENG":"We can do the treasure hunt later. I don't want my friends to get hurt because of me.","TWN":"尋寶遊戲可以以後再玩。我不想……因為我而讓朋友受傷。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그런 표정으로 말해봤자 설득력 없거든요?","JPN":"そんな顔をしながら訴えても、説得力はないですよ？","ENG":"It's not convincing at all when you say it with that expression on your face.","TWN":"你的表情完全沒有說服力欸？"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"유, 유피 일은 내가 어떻게든 해볼게.","JPN":"ゆ、ユピのことは私がなんとかする。","ENG":"I-I'll do everything I can for you.","TWN":"我、我會盡力處理好悠菲的事的。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"난 정말 괜찮아. 그러니까…….","JPN":"私は本当に大丈夫だよ。だから……","ENG":"I'm really fine. So...","TWN":"我真的沒事。所以……"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"에휴.","JPN":"はあ……","ENG":"*Sigh*","TWN":"……哀哀。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"끄앙-!","JPN":"きゃふ！？","ENG":"Waah!","TWN":"呃啊——！"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"시그마. 제가 애들한테 제일 듣기 싫어하는 말이 괜찮다는 거예요.","JPN":"シグマ。私が子どもたちから一番聞きたくない言葉は、「大丈夫」です。","ENG":"You know what, Sigma? I hate hearing kids say \\"I'm fine.\\"","TWN":"西格瑪。我最討厭小孩子對我說沒事了。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"한창 제멋대로일 나이에 괜찮은 게 어디 있겠어요? 그건 괜찮은 게 아니라 참는 거예요.","JPN":"いくらでもわがままを言っていい年なのに、大丈夫だなんて、そんなのただ我慢しているだけです。","ENG":"Kids your age are supposed to be stubborn. It's not really \\"fine.\\" You're just holding it in.","TWN":"正是任性妄為的年紀，哪裡會有好孩子？那不是沒事，而是在忍耐。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"하지만… 그럼 착한 아이가 아니게 되는걸.","JPN":"でも……私がいい子でなくなるから。","ENG":"But... I need to be a good girl.","TWN":"但是……那樣的話西格瑪就不是好孩子了。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"어라, 유피. 지금 내 이름 부른 거야?","JPN":"あれ……？　ユピ、今私の名前を呼んでくれた？","ENG":"Wait, Yuppie. Did you just say my name?","TWN":"咦，悠菲。你剛剛是叫我的名字嗎？"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"회사 때려친 지가 언젠데 계속 실장님이라 불러요, 그럼?","JPN":"とっくに会社は辞めているのに、いつまでも室長と呼ぶわけにはいきませんからね。","ENG":"I gave up on trying for the company ages ago. I don't need to continue calling you \\"Chief.\\"","TWN":"我都要離開公司了，難道還叫你室長嗎？"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"말한 김에 확실히 해두겠는데-","JPN":"はっきり言います。","ENG":"And let me make this clear.","TWN":"話到嘴邊，我就一次說清楚吧。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"본인 목소리를 내느냐가 중요하지. 착하고 나쁘고는 별반 중요하지 않아요.","JPN":"自分の口で意見を言うのが大事なのであって、いい子か悪い子かは重要じゃありません。","ENG":"What's important is whether you speak your mind or not. Being good or bad isn't all that important.","TWN":"重要的是你能否為自己發聲，是否要扮演一個好孩子並不重要。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"아이를 올바른 길로 이끌어주는 건 어디까지나 어른의 역할이예요.","JPN":"子どもを正しい方向に導くのは、大人の役目です。","ENG":"It's the adults' responsibility to lead children in the right direction.","TWN":"引導孩子走上正道始終是大人的責任。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"눈치 안 볼 나이에 눈치 보기 시작하면 커서 뭐가 되겠어요?","JPN":"子どもの時から人の顔色をうかがっていては、将来が心配です。","ENG":"What would you become if you were to start pushing things down at an age when you're not supposed to?","TWN":"在不該看人臉色的年紀就唯唯諾諾了，長大後能變成什麼樣子呢？"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"유피 양은 저를 참 나쁜 사람으로 만드시는군요.","JPN":"ユピさんはどこまでも私を悪者にしてしまうのですね。","ENG":"You're making me look like the villain here, Yuppie.","TWN":"悠菲真是把我變成一個壞人了呢。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"GAP_GOLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"아이 고집이 쇠고집이 된다고. 과잉보호가 매번 정답은 아닙니다.","JPN":"子どもを甘やかしすぎると、言うことを聞かなくなってしまう。そうは思いませんか？","ENG":"You should know that coddling children isn't the answer. They'll grow up to become overtly stubborn adults.","TWN":"孩子的倔脾氣放著不管會越來越倔。過度保護並不是每次都是正確的選擇。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"GAP_GOLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"속앓이 하는 것보다는 나아요. 잘못된 게 있다면 알려주고, 책임을 지는 건 저희 몫이니까.","JPN":"我慢ばかりで苦しい思いをするよりは、その方がマシです。間違っていることを正して、その責任を負うのが私たちの役目です。","ENG":"It's better than children suppressing their emotions. It's on us to tell them what's wrong and take responsibility.","TWN":"但總比悶在心裡好受多了。如果有什麼做錯的地方，就告訴我們，因為教育和承擔責任是我們的職責。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"GAP_GOLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"적어도 저만 그렇게 생각한 것도 아니고요.","JPN":"それに、そう思っているのは、私だけではありません。","ENG":"And I'm the only one who thinks that.","TWN":"至少不只是我一個人這麼想。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GAP_GOLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"그게 무슨…….","JPN":"それはどういう……","ENG":"What are you–","TWN":"你在做什麼……"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GAP_GOLD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"야-! 너 거기 안 서?!","JPN":"はあ！？　ちょっと待ちなさい！","ENG":"Hey! Stop right there!","TWN":"喂——！你給我站住？!"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};